window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["barbering"] = window.COURSE_LANG["barbering"] || {};
window.COURSE_LANG["barbering"]["es"] = [
  {"id":1,"q":"Para desinfectar herramientas en una barbería de California, el producto debe:","opts":["Ser cualquier jabón líquido de manos","Estar registrado con la EPA de EE. UU. y etiquetado como bactericida, fungicida y virucida","Ser alcohol común de cualquier concentración","Ser mezclado por el barbero sin etiqueta"],"re":"California exige un desinfectante registrado por la EPA cuya etiqueta indique actividad bactericida, fungicida y virucida."},
  {"id":2,"q":"Antes de poder desinfectar cualquier implemento, primero debe:","opts":["Rociarse con colonia","Limpiarse para quitar cabello y residuos visibles","Remojarse en agua común toda la noche","Calentarse en un microondas"],"re":"El desinfectante solo actúa sobre una superficie limpia, así que primero hay que quitar cabello, piel y residuos con agua y jabón."},
  {"id":3,"q":"Las herramientas no eléctricas, como peines y tijeras metálicas que pueden sumergirse, se desinfectan:","opts":["Limpiándolas con una toalla limpia","Pasándolas bajo agua corriente","Por inmersión total en un desinfectante bien preparado","Poniéndolas al sol para que se sequen"],"re":"Los implementos no eléctricos deben sumergirse por completo en el desinfectante registrado por la EPA durante el tiempo que indica la etiqueta."},
  {"id":4,"q":"Las máquinas y recortadoras eléctricas que no pueden sumergirse se desinfectan con:","opts":["Una cubeta de agua jabonosa","Aceite de cocina en la cuchilla","Sin desinfección, nunca la necesitan","Un desinfectante en aerosol o toallita registrado por la EPA"],"re":"Los artículos que no pueden sumergirse, como las máquinas y recortadoras eléctricas, se desinfectan con un aerosol o toallita registrado por la EPA."},
  {"id":5,"q":"Al sacar las herramientas de la solución desinfectante, el barbero debe:","opts":["Usar guantes o pinzas para retirarlas","Usar los dedos desnudos para ahorrar tiempo","Sacudirlas para secarlas sobre el cliente","Dejarlas en remojo todo un día"],"re":"El profesional debe usar guantes o pinzas para sacar las herramientas del desinfectante y no contaminar los implementos limpios."},
  {"id":6,"q":"La solución desinfectante de la estación debe cambiarse:","opts":["Una vez al año","Según las indicaciones del fabricante, o antes si está turbia o con residuos","Solo cuando se evapora por completo","Nunca, si todavía se ve azul"],"re":"Cambia la solución según las instrucciones del fabricante, o antes si se vuelve turbia o contiene residuos visibles."},
  {"id":7,"q":"Después de limpiar y desinfectar, los implementos deben guardarse:","opts":["Mezclados con herramientas usadas y sucias","En un bolsillo trasero con peines ya usados","En un recipiente limpio y cubierto rotulado «Limpio» o «Desinfectado»","Sueltos en el piso"],"re":"Las herramientas desinfectadas deben guardarse en un recipiente limpio y cubierto, rotulado «Limpio» o «Desinfectado», separadas de lo sucio."},
  {"id":8,"q":"Un artículo poroso de un solo uso, como un duster de cuello de madera o una tira de cuello de papel, debe:","opts":["Desinfectarse y reutilizarse con el siguiente cliente","Limpiarse con alcohol y reutilizarse","Hervirse y reutilizarse","Desecharse después de un solo cliente"],"re":"Los artículos porosos de un solo uso no pueden desinfectarse bien y deben desecharse tras usarse en un único cliente."},
  {"id":9,"q":"El nivel de descontaminación que destruye toda la vida microbiana, incluidas las esporas, es:","opts":["La limpieza","La higienización","El sacudido del polvo","La esterilización"],"re":"La esterilización destruye todos los microorganismos, incluidas las esporas bacterianas; la limpieza y la desinfección no llegan a ese nivel."},
  {"id":10,"q":"En el corte de cabello, la «elevación» se refiere a:","opts":["El ángulo al que se sostiene una sección de cabello respecto a la cabeza","Qué tan filosas están las tijeras","La temperatura del agua","Qué tan rápido gira la máquina"],"re":"La elevación es el grado (en ángulos) al que se levanta o sostiene una subsección de cabello respecto a la cabeza antes de cortar."},
  {"id":11,"q":"Un corte recto, a un solo largo y con una línea de peso marcada, se crea usando:","opts":["Una elevación de 90 grados","Elevación cero (0 grados)","Una elevación de 180 grados","Solo sobredirección constante"],"re":"A 0 grados de elevación el cabello cae a un solo nivel, formando un corte recto con una línea de peso marcada."},
  {"id":12,"q":"Cortar todo el cabello a 90 grados respecto a la cabeza generalmente produce:","opts":["Un borde grueso y recto","Más peso en las puntas","Capas uniformes de largo parejo","Ningún cambio de forma"],"re":"Sostener las secciones a 90 grados quita peso y crea capas uniformes de largo parejo en toda la cabeza."},
  {"id":13,"q":"Una guía que NO se mueve, usada en cortes rectos y con sobredirección, se llama:","opts":["Guía viajera","Guía móvil","Guía flotante","Guía estacionaria"],"re":"La guía estacionaria permanece en un solo lugar; se usa en cortes a un solo largo y al sobredirigir el cabello para ganar largo o peso."},
  {"id":14,"q":"Para lograr el largo final deseado después de que el cabello se seque, debes cortar el cabello mojado:","opts":["Un poco más largo que el largo objetivo","Exactamente en el largo objetivo","Mucho más corto que el largo objetivo","A un largo al azar"],"re":"El cabello mojado se estira y encoge al secarse, así que córtalo un poco más largo que el largo deseado, sobre todo en cabello rizado."},
  {"id":15,"q":"La técnica de máquina sobre peine suele realizarse con el cabello:","opts":["Empapado y goteando","Seco o solo ligeramente húmedo","Cubierto de gel","Recién alaciado con químico"],"re":"La técnica de máquina sobre peine funciona mejor en cabello seco o ligeramente húmedo; el cabello empapado se apelmaza y da un corte disparejo."},
  {"id":16,"q":"La «tensión» en el corte de cabello significa:","opts":["Qué tan nervioso está el cliente","La marca de tijeras usada","La cantidad de jalón aplicada a una sección al cortar","La temperatura del salón"],"re":"La tensión es la cantidad de jalón que se aplica a una sección de cabello al cortar; una tensión pareja ayuda a lograr una línea pareja y precisa."},
  {"id":17,"q":"El corte con navaja sobre el cabello generalmente se hace cuando el cabello está:","opts":["Totalmente seco","Congelado","Ligeramente aceitado","Mojado"],"re":"La navaja debe usarse sobre cabello mojado; cortar cabello seco con navaja desgarra las hebras y resulta incómodo para el cliente."},
  {"id":18,"q":"Un afeitado facial tradicional se organiza en cuántas áreas de afeitado estándar?","opts":["14","3","25","50"],"re":"El rostro se divide en 14 áreas de afeitado estándar, cada una rasurada en un orden y dirección fijos con un movimiento específico."},
  {"id":19,"q":"Al afeitar con navaja recta, la mano libre se usa para:","opts":["Sostener el teléfono del cliente","Estirar la piel y mantenerla tensa","Espantar los recortes de cabello","Ajustar la altura de la silla"],"re":"La mano opuesta (libre) estira la piel para que la hoja se deslice con seguridad y corte el vello de forma limpia."},
  {"id":20,"q":"Durante un afeitado con navaja, la hoja se sostiene contra la piel a aproximadamente:","opts":["Un ángulo de 90 grados (de frente)","Un ángulo plano de 0 grados","Aproximadamente un ángulo de corte de 30 grados","El ángulo que se sienta más rápido"],"re":"La navaja recta se sostiene a aproximadamente 30 grados respecto a la piel para un afeitado al ras y seguro."},
  {"id":21,"q":"La toalla que se aplica para ablandar la barba antes de afeitar debe estar:","opts":["Helada","Totalmente seca","Goteando desinfectante","Tibia y húmeda (toalla de vapor)"],"re":"Una toalla tibia y húmeda (de vapor) ablanda la barba y abre los folículos; debe estar cómodamente tibia, no hirviendo."},
  {"id":22,"q":"Una navaja recta que usa una hoja desechable y no requiere asentado ni suavizado se llama:","opts":["Shavette (navaja de hoja intercambiable)","Navaja alemana convencional","Asentador Feather","Cuchillo de suavizar"],"re":"La shavette usa una hoja desechable de un solo uso, por lo que no requiere asentado ni suavizado como una navaja recta convencional."},
  {"id":23,"q":"El asentado (honing) y el suavizado (stropping) son pasos de mantenimiento que sirven para:","opts":["Higienizar el peine","Mantener el filo de una navaja recta convencional afilado y liso","Secar las toallas","Mezclar la espuma"],"re":"Una navaja recta convencional se afila en una piedra de asentar y luego se suaviza en un asentador de cuero para mantener un filo parejo."},
  {"id":24,"q":"Para delinear y equilibrar una barba o bigote, el barbero debe primero:","opts":["Afeitar toda la barba","Omitir cualquier planeación","Establecer contornos limpios y simétricos que favorezcan el rostro","Usar solo una guía de corte al ras"],"re":"El diseño de vello facial comienza fijando contornos limpios y simétricos que enmarcan y equilibran los rasgos del cliente."},
  {"id":25,"q":"Si la navaja corta al cliente y aparecen unas gotas de sangre, el barbero debe:","opts":["Seguir afeitando e ignorarlo","Limpiarlo con la toalla de cuello compartida","Reutilizar la misma hoja en el siguiente cliente","Detener el servicio y ponerse guantes antes de tocar la sangre"],"re":"Detente de inmediato y ponte guantes antes de tocar la sangre; la hoja contaminada debe limpiarse y desinfectarse o desecharse."},
  {"id":26,"q":"La capa más externa del tallo del cabello, formada por escamas superpuestas, es la:","opts":["Cutícula","Corteza","Médula","Papila"],"re":"La cutícula es la capa externa, dura y superpuesta, que protege la corteza interna del cabello."},
  {"id":27,"q":"La mayor parte de la fuerza, la elasticidad y el pigmento natural del cabello se encuentra en la:","opts":["Cutícula","Corteza","Médula","Glándula sebácea"],"re":"La corteza forma la mayor parte del cabello y contiene la queratina y la melanina responsables de la fuerza, la elasticidad y el color."},
  {"id":28,"q":"El aceite natural que lubrica el cabello y el cuero cabelludo se llama sebo y lo producen las:","opts":["Glándulas sudoríparas","Bulbo piloso","Glándulas sebáceas (de grasa)","Músculo erector del pelo"],"re":"Las glándulas sebáceas secretan sebo, el aceite natural que lubrica el cabello y ayuda a proteger el cuero cabelludo."},
  {"id":29,"q":"El término técnico para la caspa común (cuero cabelludo seco y descamado) es:","opts":["Tinea capitis","Alopecia areata","Foliculitis","Pitiriasis (caspa)"],"re":"La pitiriasis es el término médico para la caspa, la descamación de la capa superior del cuero cabelludo; no es lo mismo que una infección por hongos."},
  {"id":30,"q":"La tinea capitis (tiña del cuero cabelludo) es causada por:","opts":["Un hongo","Falta de vitaminas","Un gorro apretado","Champú en seco"],"re":"La tinea capitis es una infección contagiosa por hongos (dermatofitos) del cuero cabelludo; un caso activo debe remitirse a un médico y no atenderse."},
  {"id":31,"q":"El término general para la caída o el adelgazamiento del cabello es:","opts":["Pediculosis","Alopecia","Canicie","Hipertricosis"],"re":"La alopecia es el término general para la caída del cabello; el adelgazamiento por patrón común es la alopecia androgenética (patrón masculino/femenino)."},
  {"id":32,"q":"Un beneficio principal del masaje del cuero cabelludo durante un tratamiento es que:","opts":["Cambia el color del cabello de forma permanente","Esteriliza el cuero cabelludo","Aumenta la circulación sanguínea hacia el cuero cabelludo","Elimina la necesidad de lavar con champú"],"re":"El masaje del cuero cabelludo estimula la circulación sanguínea, lo que favorece los folículos pilosos y relaja al cliente."},
  {"id":33,"q":"Si un cliente tiene piojos (pediculosis capitis), el barbero debe:","opts":["Atenderlo normalmente y no decir nada","Usar el mismo peine en el siguiente cliente","Rasurar la cabeza con una máquina sin limpiar","No realizar el servicio y remitir al cliente a la atención adecuada"],"re":"Una infestación o condición contagiosa significa que no se atiende sobre esa zona; remite al cliente y desinfecta cualquier herramienta expuesta."},
  {"id":34,"q":"Antes de un servicio de coloración por oxidación o de aclarado, el barbero debe realizar una:","opts":["Prueba de predisposición (de parche) para alergias","Revisión de crédito","Tinte de prueba en una amistad","Decoloración total sin pruebas"],"re":"La prueba de predisposición (de parche) detecta una reacción alérgica al producto y debe hacerse antes de un servicio de color por oxidación."},
  {"id":35,"q":"En la coloración del cabello, el «revelador» de peróxido de hidrógeno principalmente:","opts":["Enfría el cuero cabelludo","Aporta oxígeno para revelar el color y aclarar el pigmento natural","Agrega peso de agua","Elimina la necesidad de champú"],"re":"El revelador de peróxido de hidrógeno libera oxígeno que revela las moléculas de color y aclara el pigmento natural del cabello."},
  {"id":36,"q":"En la escala usada para el color del cabello, el «nivel» describe:","opts":["El grosor de cada hebra","La velocidad de procesamiento","Qué tan claro u oscuro es un color","La marca del producto"],"re":"El nivel es la unidad que mide qué tan claro u oscuro es un color, normalmente en una escala de 1 (más oscuro) a 10 (más claro)."},
  {"id":37,"q":"Una solución de permanente en frío ablanda el cabello rompiendo:","opts":["La superficie de la piel","Los conductos del sudor","Los vasos sanguíneos del cuero cabelludo","Los enlaces disulfuro de la corteza"],"re":"Una loción de ondulado tipo tio (permanente en frío) rompe los enlaces disulfuro de la corteza para poder remodelar el cabello en el bigudí."},
  {"id":38,"q":"Después de procesar y enjuagar una permanente, el neutralizante se aplica para:","opts":["Reformar los enlaces disulfuro y fijar el nuevo rizo","Quitar todo el color del cabello","Secar el cabello al instante","Disolver los bigudíes"],"re":"El neutralizante (un oxidante) reforma los enlaces disulfuro rotos en su nueva posición, haciendo permanente el rizo."},
  {"id":39,"q":"En un enrollado de permanente, los bigudíes de menor diámetro producen:","opts":["Ondas más sueltas y grandes","Un rizo más apretado y pequeño","Ningún rizo","Cabello más lacio"],"re":"Cuanto menor es el diámetro del bigudí, más apretado y pequeño es el rizo resultante; los bigudíes grandes dan una onda más suelta."},
  {"id":40,"q":"En comparación con una permanente de tio, un alisador de hidróxido de sodio es:","opts":["Ácido y muy suave","Neutro en pH","Fuertemente alcalino (pH alto)","El mismo químico que un neutralizante"],"re":"Los alisadores de hidróxido de sodio («sosa») son fuertemente alcalinos (pH alto), por eso alisan el cabello y exigen un manejo cuidadoso."},
  {"id":41,"q":"Por qué son importantes el análisis del cuero cabelludo y la crema base protectora antes de un alisado químico?","opts":["Aceleran la cita","Hacen que el alisador huela mejor","Fijan el precio","Los alisadores son cáusticos y pueden quemar la piel lastimada o sensible"],"re":"Los alisadores de hidróxido son cáusticos; revisar el cuero cabelludo en busca de raspaduras y aplicar una base protectora ayuda a evitar quemaduras químicas."},
  {"id":42,"q":"Una prueba preliminar de mechón antes de un servicio químico se hace para:","opts":["Ver cómo reacciona el cabello y cuánto tiempo procesar","Elegir el champú del cliente","Medir la cabeza del cliente","Cobrar producto extra"],"re":"La prueba de mechón anticipa cómo responderá el cabello a la fórmula y cuánto tiempo necesita procesar antes del servicio completo."},
  {"id":43,"q":"Una barbería debe conservar una Hoja de Datos de Seguridad (SDS) de sus productos químicos para:","opts":["Fijar precios de venta","Brindar a los trabajadores información de peligros, manejo y primeros auxilios","Programar citas","Anunciar los productos"],"re":"La SDS detalla los peligros de cada producto, su manejo seguro y los primeros auxilios, y debe estar accesible para los empleados."},
  {"id":44,"q":"La agencia de California que otorga licencias a los barberos es la:","opts":["OSHA federal","Junta de Barbería y Cosmetología (Departamento de Asuntos del Consumidor)","Servicio Postal de EE. UU.","Departamento de Agricultura"],"re":"Los barberos reciben su licencia de la Junta de Barbería y Cosmetología de California, parte del Departamento de Asuntos del Consumidor."},
  {"id":45,"q":"En California, una licencia de barbero generalmente se renueva:","opts":["Cada 6 meses","Una vez y nunca más","Cada dos años","Solo cuando te mudas"],"re":"Las licencias de barbero de California se renuevan en un ciclo de dos años."},
  {"id":46,"q":"Para presentar el examen de licencia de barbero de California a través de una escuela, el aspirante por lo general debe completar alrededor de:","opts":["100 horas","250 horas","Nada de capacitación","1,000 horas de capacitación en una escuela de barbería aprobada"],"re":"California exige alrededor de 1,000 horas de capacitación en una escuela de barbería aprobada (o 1,500 horas de aprendizaje) para presentar el examen."},
  {"id":47,"q":"La licencia de barbero de California se otorga con base en:","opts":["Un examen escrito","Una prueba de manejo","Una prueba de mecanografía","Un puntaje de crédito"],"re":"La licencia de barbero de California se basa en aprobar un examen escrito; no hay un examen práctico aparte."},
  {"id":48,"q":"Durante una inspección de la Junta a una barbería, el inspector revisa con más frecuencia que:","opts":["La música esté lo bastante fuerte","Las sillas hagan juego","Se cumplan las reglas de desinfección y saneamiento","El dueño sea amable"],"re":"Los inspectores se enfocan en el cumplimiento del saneamiento y la desinfección, que está entre las infracciones citadas con más frecuencia."},
  {"id":49,"q":"Todo recipiente y frasco de químicos en la estación debe:","opts":["Quedar totalmente sin etiqueta","Marcarse solo con una calcomanía de estrella","Estar claramente etiquetado para identificar su contenido","Guardarse junto a una llama abierta"],"re":"Todos los recipientes de químicos deben estar claramente etiquetados para que cualquiera identifique el contenido y los peligros relacionados."},
  {"id":50,"q":"Un barbero debe negarse a realizar un servicio cuando el cliente tiene:","opts":["Una condición contagiosa activa de piel o cuero cabelludo en la zona de trabajo","Cabello un poco seco","Un simple remolino","Preferencia por el cabello corto"],"re":"No atiendas sobre una condición contagiosa o infecciosa activa; remite al cliente a un médico para proteger a todos."}
];
